//stack-layout.js

import { d3_extent } from '../../../d3-constants';
import { NULL, UNDEFINED } from '../../../zc-constants';
import { Registry } from '../../../zc-registry';
import { d3_map } from '../../../d3-constants';
import { invokeFunction } from '../../../../utils/zcutils';

/**
 * @param  {Array} data          [description]
 * @param  {Function} keyAccessor   [description]
 * @param  {Function} valueAccessor [description]
 */
export var StackLayout = function(data, keyAccessor, valueAccessor) {
    var base = (this._base = 0);
    this._extent = [];
    this._data = [];
    this._batchedData = [];
    this._list = d3_map();

    if (data) {
        this.add.apply(this, arguments);
    }
};

var proto = StackLayout.prototype;

/**
 * Converts and adds the data to the layout[description]
 * @param  {Array} data          [description]
 * @param  {Function} keyAccessor   [description]
 * @param  {Function} valueAccessor [description]
 */
proto.add = function(data, keyAccessor, valueAccessor) {
    var layout = this,
        list = layout._list,
        extent = layout._extent,
        base = layout._base;

    data.forEach(d => {
        var key = keyAccessor(d),
            value = valueAccessor(d) || base,
            isRangeVal = value  instanceof Array,
            sign = +(value >= base),
            entry,
            lastY;
        
        let y0, y1;

        //Initialize y0-list
        if (!list.has(key)) {
            entry = [UNDEFINED, UNDEFINED];
            entry.key = key; //saving the key is mandatory as 1 is saved in list as "1"
            entry.values = [d];
            list.set(key, entry);
        } else {
            entry = list.get(key);
            lastY = entry.values[entry.values.length-1].y;
            entry.values.push(d);
        }


        if(isRangeVal){//range chart
            y0 = value[0];
            y1 = value[1];
            base = y0;
            value = value[1] - value[0];
        }
        // else if(d.isDummy){
        //     y0 = lastY || base,
        //     y1 = y0 + value;
        // }
        else{
            y0 = entry[sign] || base,
            y1 = y0 + value;
        }
        

        //Save y0, y values
        d.y0 = y0;
        d.y = value;
        entry[sign] = y1;

        //Find extent
        extent = d3_extent([...extent, y1, base]);
    });

    layout._extent = extent;
    layout._data = layout._data.concat(data);
    layout._batchedData.push(data);
    return layout;
};

proto.sort = function(keyAccessor, valueAccessor, sortAccessor) {
    var layout = this,
        list = layout._list,
        list_n = invokeFunction(sortAccessor, layout);
    layout._list = d3_map();
    layout.add(list_n, keyAccessor, valueAccessor);
};

/**
 * Read the extent
 * @return {Array} [description]
 */
proto.getExtent = function() {
    return this._extent;
};

Registry.setComponent('stackLayout', StackLayout);
